void applySeasonalPricing(Order order, LocalDate orderDate) {
    if (!orderDate.isBefore(LocalDate.of(orderDate.getYear(), 6, 1))
            && !orderDate.isAfter(LocalDate.of(orderDate.getYear(), 8, 31))
            && order.getTotal().isGreaterThan(Money.of(100))) {
        order.applyDiscount(0.15);
    }
}
